import { gql } from '@apollo/client';

export const queryFaqPage = gql`
  query FaqPageData($locale: String!) {
    faq(locale: $locale) {
      relevantTopicsText
      readMoreText
      showAllQuestions
      actualTopics {
        questions {
          id
          title
        }
      }
      bannerTitle
      bannerSubtitle
      bannerImage {
        url
        name
      }
    }
    questionCategories(locale: $locale) {
      title
      id
    }
  }
`;
